# ==========================================
# 4. AUDIO SPECTRUM PIPELINE (LIBROSA ENGINE)
# ==========================================
def extract_audio_features(file_path):
    """
    Loads target audio, resamples to 22050Hz, extracts a stacked 180-dimensional feature
    vector (40 MFCCs + 12 Chroma + 128 Mel Spectrogram) and reshapes to (180, 1).
    """
    import numpy as np
    import librosa
    import soundfile as sf
    try:
        # Load audio file with fixed 22050Hz sample rate
        y, sr = librosa.load(file_path, sr=22050)
        
        # Check if the audio is empty
        if len(y) == 0:
            raise ValueError("Empty audio signal sequence encountered.")
            
        stft = np.abs(librosa.stft(y))
        
        # Extract features and average over the time axis
        mfccs = np.mean(librosa.feature.mfcc(y=y, sr=sr, n_mfcc=40).T, axis=0)
        chroma = np.mean(librosa.feature.chroma_stft(S=stft, sr=sr).T, axis=0)
        mel = np.mean(librosa.feature.melspectrogram(y=y, sr=sr).T, axis=0)
        
        # Stack them to shape (180,)
        feature_vector = np.hstack((mfccs, chroma, mel))
        
        # Reshape to (180, 1)
        feature_vector_aligned = np.expand_dims(feature_vector, axis=-1)
        return y, sr, feature_vector_aligned
    except Exception as e:
        logging.error(f"Exception during feature extraction from {file_path}: {str(e)}")
        logging.error(traceback.format_exc())
        raise e

# ==========================================
# 5. ROBUST DEEP MODEL TOPOLOGY (CNN-1D)
# ==========================================
def build_ser_cnn_model(input_shape=(180, 1)):
    """
    Compiles standard 1D Convolutional Neural Network graph for Speech Emotion Recognition.
    """
    import tensorflow as tf
    from tensorflow.keras.models import Sequential
    from tensorflow.keras.layers import Conv1D, MaxPooling1D, BatchNormalization, Dropout, GlobalAveragePooling1D, Dense
    try:
        model = Sequential([
            Conv1D(64, kernel_size=3, padding='same', activation='relu', input_shape=input_shape),
            BatchNormalization(),
            MaxPooling1D(pool_size=2),
            Dropout(0.3),
            
            Conv1D(128, kernel_size=3, padding='same', activation='relu'),
            BatchNormalization(),
            MaxPooling1D(pool_size=2),
            Dropout(0.3),
            
            Conv1D(128, kernel_size=3, padding='same', activation='relu'),
            BatchNormalization(),
            Dropout(0.3),
            
            GlobalAveragePooling1D(),
            Dense(8, activation='softmax')
        ])
        model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
        return model
    except Exception as e:
        logging.error(f"Error compiling CNN-1D model structure: {str(e)}")
        logging.error(traceback.format_exc())
        raise e

@st.cache_resource(show_spinner=False)
def load_ser_model():
    """
    Attempts to load pre-trained weights from D:\MLTasks\ML task 1\models\trained_model.h5.
    Gracefully falls back to randomized initialization if any file load failures occur.
    """
    import tensorflow as tf
    # Suppress TensorFlow warnings and engine messages to keep logs clean
    os.environ['TF_CPP_MIN_LOG_LEVEL'] = '3'
    os.environ['TF_ENABLE_ONEDNN_OPTS'] = '0'
    
    models_dir = os.path.join(SCRIPT_DIR, 'models')
    weights_path = os.path.join(models_dir, 'trained_model.h5')
    
    status_msg = ""
    model = None
    
    if os.path.exists(weights_path):
        try:
            # 1. Attempt loading as a fully compiled Keras Model
            model = tf.keras.models.load_model(weights_path)
            status_msg = "Pre-trained Model (Full Graph Loaded Successfully)"
            logging.info("Pre-trained model loaded successfully via load_model.")
            return model, status_msg, False
        except Exception as e1:
            logging.warning(f"Failed to load full model graph: {str(e1)}. Attempting weights load...")
            try:
                # 2. Attempt building the model structure and loading weights manually
                model = build_ser_cnn_model(input_shape=(180, 1))
                model.load_weights(weights_path)
                status_msg = "Pre-trained Model (Weights Overlay Applied Successfully)"
                logging.info("Model weights loaded successfully onto compiled topology.")
                return model, status_msg, False
            except Exception as e2:
                logging.error(f"Failed to overlay model weights: {str(e2)}")
                logging.error(traceback.format_exc())
                
    # 3. Fallback: Initialize with random weights
    try:
        model = build_ser_cnn_model(input_shape=(180, 1))
        status_msg = "Demo Model Active (Fallback Random Weights - No pre-trained model file found)"
        logging.warning("Initialized model with random weights fallback.")
        return model, status_msg, True
    except Exception as e3:
        logging.error(f"Total fallback initialization failure: {str(e3)}")
        logging.error(traceback.format_exc())
        st.error("Severe Model Architecture Compiler Error. Check app_error.log.")
        sys.exit(1)

