# 6. PLAYBACK SIGNAL SCANNER (INTERACTIVE PLOTLY)
# ==========================================
def plot_waveform_plotly(y, sr):
    """
    Plots the time-domain waveform using Plotly and matching the dark violet theme.
    Downsamples the signal to ensure instant UI rendering.
    """
    import numpy as np
    try:
        # Downsample to ~2000 points to keep Plotly rendering fast and clean
        step = max(1, len(y) // 2000)
        y_downsampled = y[::step]
        time_axis = np.arange(len(y_downsampled)) * (step / sr)

        import plotly.graph_objects as go
        
        fig = go.Figure()
        fig.add_trace(go.Scatter(
            x=time_axis,
            y=y_downsampled,
            mode='lines',
            line=dict(color='#a78bfa', width=1.5),
            hoverinfo='skip'
        ))
        
        fig.update_layout(
            plot_bgcolor='#0f0a24',
            paper_bgcolor='#0b071a',
            font=dict(color='#e2e0ed', family='Outfit, sans-serif'),
            margin=dict(l=10, r=10, t=35, b=10),
            height=240,
            xaxis=dict(
                title='Time (seconds)',
                gridcolor='#1f1a3a',
                zerolinecolor='#1f1a3a',
                showgrid=True,
                showline=True,
                linecolor='#7c3aed'
            ),
            yaxis=dict(
                title='Amplitude',
                gridcolor='#1f1a3a',
                zerolinecolor='#1f1a3a',
                showgrid=True,
                showline=True,
                linecolor='#7c3aed'
            ),
            showlegend=False,
            title=dict(
                text='Speech Signal Time-Domain Waveform',
                font=dict(size=14, color='#ffffff', weight='bold'),
                x=0.5,
                xanchor='center'
            )
        )
        return fig
    except Exception as e:
        logging.error(f"Plotly waveform plotting failed: {str(e)}")
        logging.error(traceback.format_exc())
        return None

